class _PaymentPageState extends State<PaymentPage> {
  final BehaviorSubject<bool> _isProcessing = BehaviorSubject<bool>.seeded(false);

  Future<void> _processPayment() async {
    // Assuming you have initialized and configured the payment gateway in your package
    PaymentGateway.initialize();

    // Fetching payment details for the transaction (For demonstration purpose)
