    if (response.statusCode == 200 && response.body != null) {
      // Starting the payment process
      _isProcessing.sink.add(true);
      final result = await PaymentGateway.processPayment(jsonDecode(response.body));

      // Handle the payment result based on your use case and gateway API
      if (result['success']) {
        print('Payment Successful');
      } else {
        print('Payment Failed: ${result['message']}');
      }

      _isProcessing.sink.add(false);
    } else {
      // Handle the error when fetching payment details from the server
      print('Error fetching payment details');
      _isProcessing.sink.add(false);
    }
  }

